-- Create "users" table
CREATE TABLE "users" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "deleted_at" timestamptz NULL, "phone" character varying NULL, "email" character varying NULL, "name" character varying NOT NULL DEFAULT '', "bio" character varying NOT NULL DEFAULT '', "avatar" character varying NULL, "timezone" character varying NOT NULL DEFAULT 'UTC', "is_active" boolean NOT NULL DEFAULT false, "last_login_at" timestamptz NOT NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, PRIMARY KEY ("id"));
-- Create index "users_email_key" to table: "users"
CREATE UNIQUE INDEX "users_email_key" ON "users" ("email");
-- Create index "users_phone_key" to table: "users"
CREATE UNIQUE INDEX "users_phone_key" ON "users" ("phone");
-- Create "one_time_passwords" table
CREATE TABLE "one_time_passwords" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "code" character varying NOT NULL, "type" character varying NOT NULL, "is_used" boolean NOT NULL DEFAULT false, "expires_at" timestamptz NOT NULL, "created_at" timestamptz NOT NULL, "user_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "one_time_passwords_users_user" FOREIGN KEY ("user_id") REFERENCES "users" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- Create "user_privacies" table
CREATE TABLE "user_privacies" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "setting" character varying NOT NULL, "option" character varying NOT NULL, "updated_at" timestamptz NOT NULL, "user_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "user_privacies_users_user" FOREIGN KEY ("user_id") REFERENCES "users" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- Create index "userprivacy_user_id_setting" to table: "user_privacies"
CREATE UNIQUE INDEX "userprivacy_user_id_setting" ON "user_privacies" ("user_id", "setting");
